mapper.select:
select b.*, c.name categoryName from bundle b left join category c on b.category_id = c.id
and b.name like concat('%',#{name},'%')
and b.status = #{status}
and b.category_id = #{categoryId}
order by b.create_time desc

mapper.update:
update bundle
name = #{name}, category_id = #{categoryId}, price = #{price}, status = #{status}, description = #{description}, image = #{image}, update_time = #{updateTime}, update_user = #{updateUser},
where id = #{id}

